	trimmed := bytes.TrimSpace(raw)
	if bytes.Equal(trimmed, []byte(`""`)) || bytes.Equal(trimmed, []byte("null")) {
		return goa.PermanentError("invalid_params", "Missing required field: %s", field)
	}
	return nil
